import{_ as a,o as d,c as i,O as t}from"./chunks/framework.3442b110.js";const h=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh/FAQ.md","filePath":"zh/FAQ.md","lastUpdated":1756871878000}'),o={name:"zh/FAQ.md"};function r(l,e,s,c,n,g){return d(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="_1-数据表-table-和视图-view-的关系" tabindex="-1">1. 数据表 (Table) 和视图 (View) 的关系 <a class="header-anchor" href="#_1-数据表-table-和视图-view-的关系" aria-label="Permalink to &quot;1. 数据表 (Table) 和视图 (View) 的关系&quot;">​</a></h2><ul><li><strong>数据表</strong>：可以将数据表理解成一个<code>数据源</code>，它负责维护数据与数据之间的联系，并不涉及 UI 展示(如字段顺序、记录顺序等)</li><li><strong>视图</strong>：不同的视图（如表格视图 <code>GridView</code>、看板视图 <code>KanbanView</code> 等）均是以某种 <code>UI 的呈现形式</code>来消费这个<code>数据源</code></li></ul><h2 id="_2-为什么-table-模块中-getrecordidlist-和-getfieldidlist-方法拿到的记录列表和字段列表均是无序的-如何拿到有序的记录列表和字段列表" tabindex="-1">2. 为什么 <code>Table</code> 模块中 <code>getRecordIdList</code> 和 <code>getFieldIdList</code> 方法拿到的记录列表和字段列表均是无序的？如何拿到有序的记录列表和字段列表？ <a class="header-anchor" href="#_2-为什么-table-模块中-getrecordidlist-和-getfieldidlist-方法拿到的记录列表和字段列表均是无序的-如何拿到有序的记录列表和字段列表" aria-label="Permalink to &quot;2. 为什么 `Table` 模块中 `getRecordIdList` 和 `getFieldIdList` 方法拿到的记录列表和字段列表均是无序的？如何拿到有序的记录列表和字段列表？&quot;">​</a></h2><p>原因解释可以参考上面问题的答案，不同类型的 <code>View</code> 模块中均存在 <a href="./api/view/grid#getvisiblerecordidlist">getVisibleRecordIdList</a> 和 <a href="./api/view/grid#getvisiblefieldidlist">getVisibleFieldIdList</a> 方法，如果希望拿到<code>有序</code>的记录和字段列表，请通过这两个方法获取。</p><h2 id="_3-bridge-getuserid-方法获取到的-userid-能直接在飞书开放平台消费使用吗" tabindex="-1">3. <a href="./../zh/api/bridge#getuserid">Bridge.getUserId</a> 方法获取到的 userId 能直接在飞书开放平台消费使用吗？ <a class="header-anchor" href="#_3-bridge-getuserid-方法获取到的-userid-能直接在飞书开放平台消费使用吗" aria-label="Permalink to &quot;3. [Bridge.getUserId](../zh/api/bridge.md#getuserid) 方法获取到的 userId 能直接在飞书开放平台消费使用吗？&quot;">​</a></h2><p><strong>不可以</strong>，该接口获取到的 <code>userId</code> 和飞书开放平台中的 <code>userId</code> 并非一一对应的关系，<strong>两者相互独立，请勿混用</strong>。</p><h2 id="_4-为什么在高级权限下分配了-table-权限-调用权限检查-api-却返回-false" tabindex="-1">4. 为什么在高级权限下分配了 Table 权限，调用权限检查 API 却返回 false？ <a class="header-anchor" href="#_4-为什么在高级权限下分配了-table-权限-调用权限检查-api-却返回-false" aria-label="Permalink to &quot;4. 为什么在高级权限下分配了 Table 权限，调用权限检查 API 却返回 false？&quot;">​</a></h2><p>当通过高级权限给用户分配了 Table 的编辑和管理权限后，调用 <code>getPermission</code> API 检查 Table 权限时返回 false，这是符合预期的设计。</p><ul><li><strong>原因</strong>：Table 实体本身没有 <code>manageable</code> 权限点位，且 <code>editable</code> 在高级权限场景下会返回 false</li><li><strong>解决方案</strong>：如需检查具体的行、列或视图权限，请将实体类型从 <code>Table</code> 改为具体的实体类型，如 <code>Record</code>、<code>Field</code> 或 <code>View</code></li></ul>',10)])])}const u=a(o,[["render",r]]);export{h as __pageData,u as default};
